#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long u[12010],v[12010],w[12010];
vector<pair<long long,long long>> mp[6010];
long long dis[3010][3010],d[6010];
bool vis[6010];
void bellman_ford(long long x)
{
    memset(d,0x3f,sizeof(d));
    d[x]=0;
    for(long long x=1;x<=n+1;x++)
    {
        for(long long i=1;i<=n+m;i++)
        {
            if(d[v[i]]>d[u[i]]+w[i])
            {
                d[v[i]]=d[u[i]]+w[i];
            }
        }
    }
    for(long long i=1;i<=n+m;i++)
    {
        if(d[v[i]]>d[u[i]]+w[i])
        {
            printf("-1");
            exit(0);
        }
    }
}
void dijkstra(long long st)
{
    memset(dis[st],0x3f,sizeof(dis[st]));
    memset(vis,0,sizeof(vis));
    dis[st][st]=0;
    priority_queue<pair<long long,long long>> q;
    q.push(make_pair(0,st));
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[st][v]>dis[st][t]+val)
            {
                dis[st][v]=dis[st][t]+val;
                q.push(make_pair(-dis[st][v],v));
            }
        }
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld%lld",&u[i],&v[i],&w[i]);
    }
    for(long long i=1;i<=n;i++)
    {
        u[i+m]=0;
        v[i+m]=i;
        w[i+m]=0;
    }
    bellman_ford(0);
    for(long long i=1;i<=m;i++)
    {
        w[i]+=d[u[i]]-d[v[i]];
    }
    for(long long i=1;i<=m;i++)
    {
        mp[u[i]].push_back(make_pair(v[i],w[i]));
    }
    for(long long i=1;i<=n;i++)
    {
        dijkstra(i);
        long long ans=0;
        for(long long j=1;j<=n;j++)
        {
            if(dis[i][j]>1e18)
            {
                dis[i][j]=1e9-d[j]+d[i];
            }
            ans+=j*(dis[i][j]+d[j]-d[i]);
        }
        printf("%lld\n",ans);
    }
    return 0;
}
